using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides web search capability to the agent using the Brave Search API.
/// Falls back to a simulated search if no API key is configured.
/// </summary>
public sealed class WebSearchTool(IHttpClientFactory httpClientFactory, ILogger<WebSearchTool> logger)
{
    [Description("Searches the web for information on a given query. Returns a list of results with titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);
        logger.LogDebug("Web search: Query={Query}, MaxResults={MaxResults}", query, maxResults);

        var apiKey = Environment.GetEnvironmentVariable("BRAVE_SEARCH_API_KEY");
        if (string.IsNullOrWhiteSpace(apiKey))
        {
            logger.LogWarning("BRAVE_SEARCH_API_KEY not set — returning simulated results");
            return GetSimulatedResults(query, maxResults);
        }

        try
        {
            var client = httpClientFactory.CreateClient("BraveSearch");
            client.DefaultRequestHeaders.Add("X-Subscription-Token", apiKey);
            client.DefaultRequestHeaders.Add("Accept", "application/json");

            var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={maxResults}";
            var response = await client.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            using var doc = await JsonDocument.ParseAsync(
                await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

            var results = new List<object>();
            if (doc.RootElement.TryGetProperty("web", out var web) &&
                web.TryGetProperty("results", out var webResults))
            {
                foreach (var item in webResults.EnumerateArray().Take(maxResults))
                {
                    results.Add(new
                    {
                        title = item.GetProperty("title").GetString(),
                        url = item.GetProperty("url").GetString(),
                        snippet = item.TryGetProperty("description", out var desc) ? desc.GetString() : ""
                    });
                }
            }

            logger.LogDebug("Web search returned {Count} results", results.Count);
            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            logger.LogError(ex, "Web search failed for query: {Query}", query);
            return JsonSerializer.Serialize(new { error = "Search request failed", message = ex.Message });
        }
    }

    private static string GetSimulatedResults(string query, int maxResults)
    {
        var results = Enumerable.Range(1, maxResults).Select(i => new
        {
            title = $"Result {i} for '{query}'",
            url = $"https://example.com/result-{i}",
            snippet = $"This is a simulated search result about '{query}'. " +
                      $"In a production environment, set BRAVE_SEARCH_API_KEY to get real results."
        });

        return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking capability so the agent can record, list, and
/// summarize findings gathered during research.
/// </summary>
public sealed class NoteTool(ILogger<NoteTool> logger)
{
    private readonly List<(string Topic, string Content)> _notes = [];

    [Description("Saves a research note with a topic label and content. Use this to record important findings from web searches.")]
    public string SaveNote(
        [Description("Short topic label for the note (e.g. 'Key finding', 'Statistic', 'Source')")] string topic,
        [Description("The content of the note")] string content)
    {
        _notes.Add((topic, content));
        logger.LogDebug("Note saved: Topic={Topic}, ContentLength={Length}", topic, content.Length);
        return $"Note saved under '{topic}'. Total notes: {_notes.Count}.";
    }

    [Description("Lists all saved research notes with their topic labels.")]
    public string ListNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        for (var i = 0; i < _notes.Count; i++)
        {
            var (topic, content) = _notes[i];
            sb.AppendLine($"\n--- Note {i + 1}: {topic} ---");
            sb.AppendLine(content);
        }

        return sb.ToString();
    }

    [Description("Clears all saved notes. Use when starting research on a new topic.")]
    public string ClearNotes()
    {
        var count = _notes.Count;
        _notes.Clear();
        logger.LogDebug("Cleared {Count} notes", count);
        return $"Cleared {count} note(s).";
    }
}

