    private readonly List<(string Topic, string Content)> _notes = [];

    [Description("Saves a research note with a topic label and content. Use this to record important findings from web searches.")]
    public string SaveNote(
        [Description("Short topic label for the note (e.g. 'Key finding', 'Statistic', 'Source')")] string topic,
        [Description("The content of the note")] string content)
    {
        _notes.Add((topic, content));
        logger.LogDebug("Note saved: Topic={Topic}, ContentLength={Length}", topic, content.Length);
        return $"Note saved under '{topic}'. Total notes: {_notes.Count}.";
    }

    [Description("Lists all saved research notes with their topic labels.")]
    public string ListNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        for (var i = 0; i < _notes.Count; i++)
        {
            var (topic, content) = _notes[i];
            sb.AppendLine($"\n--- Note {i + 1}: {topic} ---");
            sb.AppendLine(content);
        }

        return sb.ToString();
    }

    [Description("Clears all saved notes. Use when starting research on a new topic.")]
    public string ClearNotes()
    {
        var count = _notes.Count;
        _notes.Clear();
        logger.LogDebug("Cleared {Count} notes", count);
        return $"Cleared {count} note(s).";
    }
}

