using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

builder.Logging.SetMinimumLevel(LogLevel.Warning);

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddSingleton<WebSearchTool>();
builder.Services.AddSingleton<NoteTool>();
builder.Services.AddHttpClient("BraveSearch");

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(apiKey, modelId)
    .UseFunctionInvocation(o => o.MaximumIterationsPerRequest = 20));

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var webSearch = host.Services.GetRequiredService<WebSearchTool>();
var noteTool = host.Services.GetRequiredService<NoteTool>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();
var logger = loggerFactory.CreateLogger("ResearchAgent");

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.ListNotes),
    AIFunctionFactory.Create(noteTool.ClearNotes),
};

const string systemPrompt = """
    You are a research agent. Your job is to thoroughly research a topic
    provided by the user using the available tools, then produce a clear summary.

    Workflow:
    1. Use SearchWebAsync to find relevant information (run multiple searches
       with different queries to get broad coverage).
    2. Use SaveNote to record key findings, statistics, and source URLs.
    3. Use ListNotes to review everything you've gathered.
    4. Produce a well-structured summary with:
       - An overview paragraph
       - Key findings as bullet points
       - Sources cited with URLs

    Be thorough — perform at least 2-3 different searches to cover the topic
    from multiple angles. Always cite your sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: systemPrompt,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking tools",
    tools: tools,
    loggerFactory: loggerFactory);

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent (GPT-4o)        ║");
Console.WriteLine("║  Type a topic to research, or 'quit'.   ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic > ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching... (the agent will search the web and take notes)");
    Console.ResetColor();

    try
    {
        var session = await agent.CreateSessionAsync(
            conversationId: Guid.NewGuid().ToString());

        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session);

        logger.LogDebug("Agent finished: MessageCount={Count}", response.Messages.Count);

        var summary = response.Text;

        Console.WriteLine();
        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══");
        Console.ResetColor();
        Console.WriteLine(summary ?? "The agent did not produce a summary.");
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

