using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides web search capability to the agent using the Brave Search API.
/// Falls back to a simulated search if no API key is configured.
/// </summary>
public sealed class WebSearchTool(IHttpClientFactory httpClientFactory, ILogger<WebSearchTool> logger)
{
    [Description("Searches the web for information on a given query. Returns a list of results with titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);
        logger.LogDebug("Web search: Query={Query}, MaxResults={MaxResults}", query, maxResults);

        var apiKey = Environment.GetEnvironmentVariable("BRAVE_SEARCH_API_KEY");
        if (string.IsNullOrWhiteSpace(apiKey))
        {
            logger.LogWarning("BRAVE_SEARCH_API_KEY not set — returning simulated results");
            return GetSimulatedResults(query, maxResults);
        }

        try
        {
            var client = httpClientFactory.CreateClient("BraveSearch");
            client.DefaultRequestHeaders.Add("X-Subscription-Token", apiKey);
            client.DefaultRequestHeaders.Add("Accept", "application/json");

